noncompliant:
// Noncompliant - String contains hidden control characters
string text = "Hello World"; // Contains invisible U+200B zero-width space

// Noncompliant - Raw tab character in string
string path = "C:\Users	\Documents"; // Tab character instead of escape sequence

// Noncompliant - Non-breaking space that looks like regular space
string name = "John Doe"; // Contains NBSP instead of regular space

compliant:
// Compliant - Using escape sequences
string text = "Hello\nWorld"; // Explicit newline
string path = "C:\\Users\\Documents"; // Escaped backslashes

// Compliant - Using verbatim strings
string path = @"C:\Users\Documents";

// Compliant - Using Unicode escape for special characters
string text = "Value\u0009is"; // Explicit tab using Unicode escape
